css:
.loader {
  color: var(--loader-color, #f59e0b);
  --loader-secondary-color: #fde68a;
  --loader-bg: #ffffff;
width:9px;
height: 9px;
background: currentColor;
color: currentColor;
box-shadow:
-18px -9px,0 -9px,18px -9px,
-18px 0 , 18px 0 ,
-18px 9px,0 9px,18px 9px,
-18px 18px,0 18px,18px 18px;
animation: l30 2s infinite;
}
@keyframes l30 {
10% {
box-shadow:
-18px -9px,0 -9px,18px -9px,
-18px 0 , 18px 0 ,
-18px 9px 0 2px,0 9px,18px 9px 0 2px,
-18px 18px,0 18px,18px 18px;
}
20% {
box-shadow:
-18px -9px,0 -9px,18px -9px,
-18px 0 , 18px 0 ,
-18px 9px,0 9px,18px 9px 0 2px,
-18px 18px 0 2px,0 18px,18px 18px;
}
30% {
box-shadow:
-18px -9px,0 -9px,18px -9px,
-18px 0 0 2px, 18px 0 ,
-18px 9px,0 9px 0 2px,18px 9px,
-18px 18px 0 2px,0 18px,18px 18px 0 2px;
}
40% {
box-shadow:
-18px -9px,0 -9px ,18px -9px,
-18px 0 0 2px, 18px 0 0 2px,
-18px 9px,0 9px,18px 9px,
-18px 18px,0 18px,18px 18px 0 2px;
}
50% {
box-shadow:
-18px -9px,0 -9px,18px -9px,
-18px 0 , 18px 0 0 2px,
-18px 9px 0 2px,0 9px,18px 9px,
-18px 18px,0 18px,18px 18px;
}
60% {
box-shadow:
-18px -9px,0 -9px 0 2px,18px -9px,
-18px 0 , 18px 0 ,
-18px 9px 0 2px,0 9px,18px 9px,
-18px 18px 0 2px,0 18px,18px 18px;
}
70% {
box-shadow:
-18px -9px,0 -9px 0 2px,18px -9px 0 2px,
-18px 0 , 18px 0 ,
-18px 9px,0 9px,18px 9px,
-18px 18px 0 2px,0 18px,18px 18px;
}
80% {
box-shadow:
-18px -9px 0 2px,0 -9px,18px -9px,
-18px 0 , 18px 0 ,
-18px 9px,0 9px,18px 9px,
-18px 18px,0 18px,18px 18px 0 2px;
}
90% {
box-shadow:
-18px -9px 0 2px,0 -9px,18px -9px,
-18px 0 , 18px 0 ,
-18px 9px,0 9px 0 2px,18px 9px,
-18px 18px,0 18px,18px 18px 0 2px;
}
}
